            for(let i=0;i<24;i++){const a=i*TAU/24; const r=f.radius*(.88+.13*Math.sin(i*1.7+matchClock*3)); const x=Math.cos(a)*r,y=Math.sin(a)*r; i?ctx.lineTo(x,y):ctx.moveTo(x,y);}
