                    p.hit = true;
                    if (p.dmg > 0) window.apexDealHybridNumericDamage ? window.apexDealHybridNumericDamage(target, owner, p.dmg, 'card-throw') : target.takeDamage(p.dmg, owner, 'card-throw');
