      const dmg=C.GOAL_DRIVE_FIXED_DAMAGE+C.GOAL_DRIVE_MAX_CARRY_DAMAGE*clamp(d.soccerCarryDistance/GAME_SIZE,0,1);
      e.takeDamage(dmg,f,'soccer-goal-drive');
