      d.soccerCarryActive=false; d.soccerShotResolving=false; e.data.soccerForcedBy=null;
      b.skillShot=null; b.damageArmed=false; b.state=SOCCER_FREE_BALL; b.speed=C.BALL_MAX_SPEED*.65;
