          if(e && dist(f.x,f.y,e.x,e.y)<f.radius+e.radius+18 && !R.hitIds[e.id]){ R.hitIds[e.id]=true; e.takeDamage(R.damage,f,'flash-rage-zigzag'); spawnShockwave(e.x,e.y,'#fff06b',120); }
