        if (!Number.isFinite(f.hp)) f.hp = Math.max(1, f.maxHp || 100);
        const r = f.radius || 40;
        f.x = clamp(f.x, r, GAME_SIZE-r); f.y = clamp(f.y, r, GAME_SIZE-r);
        if (!f.dir || !Number.isFinite(f.dir.x) || !Number.isFinite(f.dir.y)) f.dir = norm(rand(-1,1), rand(-1,1));
