    const hit=pick((a,b)=>(b.result.biggest||0)-(a.result.biggest||0));
    const fast=pick((a,b)=>(a.result.duration||999)-(b.result.duration||999));
    const clutch=pick((a,b)=>(a.result.winnerHp||999)-(b.result.winnerHp||999));
