      const t0 = i/segs, t1 = (i+1)/segs;
      const x0 = lerp(tr.x1,tr.x2,t0), y0 = lerp(tr.y1,tr.y2,t0);
      const x1 = lerp(tr.x1,tr.x2,t1), y1 = lerp(tr.y1,tr.y2,t1);
      const mx = (x0+x1)/2 + Math.sin(i*2.1)*20;
