      if (img && img.complete && img.naturalWidth) ctx.drawImage(img,0,0,GAME_SIZE,GAME_SIZE);
      else { ctx.fillStyle='rgba(70,30,160,.35)'; ctx.fillRect(0,0,GAME_SIZE,GAME_SIZE); }
