        const img = gImg(`planet${planetIndex}`);
        const ang = nowSec() * speed + i * TAU / 4;
        const px = Math.cos(ang) * rr;
        const py = Math.sin(ang) * rr;
        const size = lerp(PLANET_ORBIT_SIZE * 1.14, 28, t);
